INSERT INTO `Kits` VALUES (1,'1.5KW Home Solar System','Compact  residential solar kit for lighting, phone charging, router backup, fan use, and small daily loads. Designed for starter homes, shops, and off-grid rooms.','/uploads/kits/1-5kw-kit-1782550919719-550521652.png','home-solar-system-1-5kw',1,'in_stock','2026-06-26 09:23:30','2026-06-28 09:47:26'),(2,'3.0KW Home Solar System','Entry  home solar package for small houses, shops, classrooms, and backup power with panels, inverter, LiFePO4 storage, mounting, cabling, and connectors.','/uploads/kits/3kw-1782468021741-636315567.png','home-solar-system-3kw',1,'in_stock','2026-06-26 09:23:30','2026-06-28 09:47:26'),(3,'6.2KW Home Solar System','Mid-size household and small business kit aligned to the 6.2KW home solar system family for refrigeration, lighting, entertainment, fans, and moderate appliance loads.',NULL,'home-solar-system-6kw',1,'in_stock','2026-06-26 09:23:30','2026-06-26 09:23:30'),(4,'6.2KW-10KW Home Solar System','Large residential and light commercial solar system aligned to  6.2KW-10KW capacity bands with higher inverter capacity and scalable battery storage.','/uploads/kits/3kw2w-1782470388340-848507547.png','home-solar-system-10kw',1,'in_stock','2026-06-26 09:23:30','2026-06-28 09:47:26'),(5,'20KW-30KW Home Solar System','Large villa, estate, office, or compound solar system aligned to  20KW-30KW home solar system packaging.',NULL,'home-solar-system-20kw',0,'in_stock','2026-06-26 09:23:30','2026-06-28 09:47:26'),(6,'30KW Home and Facility Solar System','High-capacity solar system for compounds, facilities, farms, and offices with three-phase inverter capability and larger PV array sizing.',NULL,'home-solar-system-30kw',0,'in_stock','2026-06-26 09:23:30','2026-06-26 09:23:30'),(7,'30KW-50KW Commercial Solar System','Commercial solar kit for shops, offices, hotels, clinics, schools, warehouses, and small factories.',NULL,'commercial-solar-system-30-50kw',1,'in_stock','2026-06-26 09:23:30','2026-06-26 09:23:30'),(8,'60KW-100KW Commercial Solar System','Higher-capacity commercial solar kit for factories, malls, hotels, schools, and business facilities needing stronger energy cost control.',NULL,'commercial-solar-system-60-100kw',1,'in_stock','2026-06-26 09:23:30','2026-06-26 09:23:30'),(9,'120KW-180KW Industrial Solar System','Industrial solar package for warehouses, manufacturing, production sites, and high-consumption facilities.',NULL,'industrial-solar-system-120-180kw',0,'in_stock','2026-06-26 09:23:30','2026-06-26 09:23:30'),(10,'250KW-500KW Industrial Solar System','Project-scale solar and storage solution for industrial parks, large factories, logistics bases, and high-demand commercial sites.',NULL,'industrial-solar-system-250-500kw',0,'in_stock','2026-06-26 09:23:30','2026-06-26 09:23:30'),(11,'500KW Container Solar System','Containerized solar and storage solution for industrial power, microgrids, EV charging depots, and remote infrastructure.',NULL,'container-solar-system-500kw',0,'in_stock','2026-06-26 09:23:30','2026-06-26 09:23:30'),(12,'1MW Container Solar System','Large-scale containerized PV plus ESS solution for industrial sites, charging depots, and utility support projects.',NULL,'container-solar-system-1000kw',0,'in_stock','2026-06-26 09:23:30','2026-06-26 09:23:30'),(13,'100kWh Industrial and Commercial ESS Kit','Battery energy storage package for backup, peak shaving, solar self-consumption, and commercial energy stability.','/uploads/kits/ffddfdfd-1782469117078-693955843.png','ic-ess-100kwh',1,'in_stock','2026-06-26 09:23:30','2026-06-26 10:18:38'),(14,'200kWh Industrial and Commercial ESS Kit','Expanded ESS package for factories, hotels, campuses, telecom, and commercial facilities requiring longer runtime.',NULL,'ic-ess-200kwh',0,'in_stock','2026-06-26 09:23:30','2026-06-26 09:23:30'),(15,'500kWh Industrial and Commercial ESS Kit','High-capacity ESS solution for larger facilities, microgrids, EV charging stations, and PV storage projects.',NULL,'ic-ess-500kwh',0,'in_stock','2026-06-26 09:23:30','2026-06-26 09:23:30'),(16,'1500W Solar Power Generator Kit','Portable solar power generator kit for emergency backup, outdoor work, camping, small shops, and mobile power.','/uploads/kits/3kw2w-1782468643894-557340461.png','solar-generator-1500w',1,'in_stock','2026-06-26 09:23:30','2026-06-26 10:10:45'),(17,'3000W Solar Power Generator Kit','Portable and semi-mobile solar power generator package for stronger backup, field teams, and small business use.','/uploads/kits/3kw2w-1782468569721-709798468.png','solar-generator-3000w',1,'in_stock','2026-06-26 09:23:30','2026-06-26 10:09:30'),(18,'6200W Solar Power Generator Kit','High-output solar power generator kit for remote sites, resilient household loads, and field operations.',NULL,'solar-generator-6200w',0,'in_stock','2026-06-26 09:23:30','2026-06-26 09:23:30'),(19,'2.5KWh-17KWh Powerwall Battery Kit','Wall-mounted LiFePO4 powerwall battery family paired with compatible hybrid inverter options for residential solar backup.',NULL,'powerwall-battery-kit',0,'in_stock','2026-06-26 09:23:30','2026-06-26 09:23:30'),(20,'Rack Mounted Battery Kit','Rack-mounted LiFePO4 battery package for telecom, server room, commercial backup, and modular solar storage.',NULL,'rack-battery-kit',0,'in_stock','2026-06-26 09:23:30','2026-06-26 09:23:30'),(21,'Solar Light and Fan Home Kit','Integrated home kit with solar panel, rechargeable battery, LED lighting, solar fan, and mobile charging for daily off-grid use.',NULL,'solar-light-fan-home-kit',1,'in_stock','2026-06-26 09:23:30','2026-06-26 09:23:30'),(22,'Agri Solar Kit','Solar kit for farms, irrigation support, borehole sites, livestock operations, rural lighting, and agricultural productivity.','/uploads/kits/agrisolar-1782469474487-455526562.png','agri-solar',1,'in_stock','2026-06-26 09:23:30','2026-06-26 10:24:35'),(23,'Solar EV Station Kit','PV plus ESS plus EV charging station kit for commercial parking, fleet yards, logistics bases, and clean transport projects.',NULL,'solar-ev-station',1,'in_stock','2026-06-26 09:23:30','2026-06-26 09:23:30'),(24,'3KW-8KW US Standard Dual Output Solar System','US standard dual-output residential solar system family for split load planning, backup circuits, and medium home energy independence.',NULL,'us-standard-dual-output-solar-system-3-8kw',0,'in_stock','2026-06-26 09:23:30','2026-06-26 09:23:30'),(25,'10KW-20KW US Standard Split-Phase Solar System','US standard split-phase solar system family for higher residential and light commercial requirements with larger PV input and lithium battery storage.',NULL,'us-standard-split-phase-solar-system-10-20kw',0,'in_stock','2026-06-26 09:23:30','2026-06-26 09:23:30'),(26,'High Voltage Rack Battery Kit','High-voltage rack battery system for three-phase solar storage and larger commercial energy projects.',NULL,'high-voltage-rack-battery-kit',0,'in_stock','2026-06-26 09:23:30','2026-06-26 09:23:30'),(27,'Residential ESS 6kW / 5.12kWh','Single-phase residential energy storage kit with a 6kW hybrid inverter and 5.12kWh LiFePO4 battery for solar self-consumption, essential-load backup, and time-of-use operation.',NULL,'residential-ess-6kw-5-12kwh',1,'in_stock','2026-06-28 09:47:26','2026-06-28 09:47:26'),(28,'Residential ESS 6kW / 10.24kWh','Extended-runtime single-phase residential energy storage kit with a 6kW hybrid inverter and 10.24kWh LiFePO4 battery.',NULL,'residential-ess-6kw-10-24kwh',1,'in_stock','2026-06-28 09:47:26','2026-06-28 09:47:26'),(29,'Three-Phase ESS 15kW / 51.2kWh','Commercial three-phase energy storage kit with a 15kW high-voltage hybrid inverter, 51.2kWh battery rack, BMS communication, and energy management.',NULL,'three-phase-ess-15kw-51-2kwh',1,'in_stock','2026-06-28 09:47:26','2026-06-28 09:47:26');
/*!40000 ALTER TABLE `Kits` ENABLE KEYS */;
